+		List<Object> expectedOutput = new ArrayList<>();
+		expectedOutput.add(record(2L, "2a2", 2L, "2b7"));
+		expectedOutput.add(record(1L, "1a3", 1L, "1b12"));
+
+		assertor.assertOutputEquals("output wrong.", expectedOutput, testHarness.getOutput());
+		testHarness.close();
+	}
